import os
import boto3
from botocore.exceptions import ClientError
import joblib
import logging

logger = logging.getLogger(__name__)

def get_latest_model_version(bucket_name, model_key):
    s3 = boto3.client('s3')
    try:
        response = s3.list_objects_v2(Bucket=bucket_name, Prefix=model_key)
        if 'Contents' not in response:
            raise Exception(f"No objects found for key {model_key}")
        
        latest_object = max(response['Contents'], key=lambda x: x['LastModified'])
        return latest_object['Key']
    except ClientError as e:
        logger.error(f"Error fetching latest model version: {e}")
        raise

def load_model_from_s3(bucket_name, model_path):
    s3 = boto3.client('s3')
    try:
        logger.info(f"Loading model from s3://{bucket_name}/{model_path}")
        s3.download_file(bucket_name, model_path, '/tmp/model.pkl')
        model = joblib.load('/tmp/model.pkl')
        logger.info("Model loaded successfully")
        return model
    except ClientError as e:
        logger.error(f"Error loading model from S3: {e}")
        raise
    except Exception as e:
        logger.error(f"Error loading model: {e}")
        raise

def main():
    model_path = os.environ.get('MODEL_PATH')
    if not model_path:
        raise ValueError("MODEL_PATH environment variable not set")
    
    bucket_name, model_key = model_path.split('/', 1)
    
    try:
        latest_model_key = get_latest_model_version(bucket_name, model_key)
        model = load_model_from_s3(bucket_name, latest_model_key)
        logger.info("Model service ready")
        return model
    except Exception as e:
        logger.error(f"Failed to load model: {e}")
        raise

if __name__ == "__main__":
    model = main()